def _send_and_recv_json(sock: socket.socket, msg: str, timeout: float = 0.5):
    """Send a command and try to receive a JSON response. Returns parsed object or None.
    Ensures utf-8 encoding/decoding as required.
    """
    try:
        sock.settimeout(timeout)
        sock.sendall(msg.encode("utf-8"))
        data = sock.recv(4096)
        if not data:
            return None
        text = data.decode("utf-8").strip()
        # Try simple JSON parsing; if it fails, attempt to extract a JSON array/object
        try:
            return json.loads(text)
        except json.JSONDecodeError:
