            # This is a best-effort fallback in case of extra whitespace/newlines
            start_obj = text.find('{')
            end_obj = text.rfind('}')
            start_arr = text.find('[')
            end_arr = text.rfind(']')
            candidate = None
            if start_arr != -1 and end_arr != -1 and end_arr > start_arr:
                candidate = text[start_arr:end_arr+1]
            elif start_obj != -1 and end_obj != -1 and end_obj > start_obj:
